package src.blocks.forms.org.apache.cocoon.forms.formmodel;

public class MultiValueFieldDefinitionBuilder extends AbstractDatatypeWidgetDefinitionBuilder { public WidgetDefinition buildWidgetDefinition ( Element widgetElement ) throws Exception { MultiValueFieldDefinition definition = new MultiValueFieldDefinition ( ) ; setCommonProperties ( widgetElement , definition ) ; setDisplayData ( widgetElement , definition ) ; setValidators ( widgetElement , definition ) ; Element datatypeElement = DomHelper . getChildElement ( widgetElement , Constants . DEFINITION_NS , "datatype" ) ; if ( datatypeElement == null ) { throw new Exception ( "A nested datatype element is required for the widget " + widgetElement . getTagName ( ) + " with id \"" + definition . getId ( ) + "\" at " + DomHelper . getLocation ( widgetElement ) ) ; } Datatype datatype = datatypeManager . createDatatype ( datatypeElement , true ) ; definition . setDatatype ( datatype ) ; boolean hasSelectionList = buildSelectionList ( widgetElement , definition ) ; if ( ! hasSelectionList ) throw new Exception ( "Error: multivaluefields always require a selectionlist at " + DomHelper . getLocation ( widgetElement ) ) ; Iterator iter = buildEventListeners ( widgetElement , "on-value-changed" , ValueChangedListener . class ) . iterator ( ) ; while ( iter . hasNext ( ) ) { definition . addValueChangedListener ( ( ValueChangedListener ) iter . next ( ) ) ; } return definition ; } }